+      {/* ======================================================== */}
+      {/* MAIN CONTENT AREA */}
+      {/* ======================================================== */}
+      <main className="flex-1 p-4 md:p-8 overflow-y-auto no-scrollbar relative min-h-0">
+        {children}
+      </main>
+
+    </div>
+  );
+}
