+const getAvatarBg = (name: string) => {
+  const colors = [
+    "bg-red-500",
+    "bg-pink-500",
+    "bg-purple-500",
+    "bg-indigo-500",
+    "bg-blue-500",
+    "bg-sky-500",
+    "bg-teal-500",
+    "bg-emerald-500",
+    "bg-amber-500",
+    "bg-orange-500",
+  ];
+  let sum = 0;
+  for (let i = 0; i < name.length; i++) {
+    sum += name.charCodeAt(i);
+  }
+  return colors[sum % colors.length];
+};
