+  let sum = 0;
+  if (name) {
+    for (let i = 0; i < name.length; i++) {
+      sum += name.charCodeAt(i);
+    }
+  }
+  return themes[sum % themes.length];
+};
+
+export default function CRMDashboardPage() {
