+import { Suspense } from "react";
+import { DashboardShellTest } from "./DashboardShellTest";
+import { getAiSettings } from "@/features/ai/actions";
+import { getKesherSettings } from "@/features/kesher/actions";
+import { getGlobalSettings } from "@/features/settings/actions";
+import { adminDb } from "@/lib/firebase-admin";
+import { auth } from "@/lib/auth";
+
+export const dynamic = 'force-dynamic';
+
+interface DashboardLayoutProps {
+  children: React.ReactNode;
+  modal: React.ReactNode;
+}
+
+export default async function DashboardLayout({
+  children,
+  modal,
+}: DashboardLayoutProps) {
+  const [aiSettings, kesherSettings, dbActive, globalSettings] = await Promise.all([
+    (async () => {
+      if (process.env.GEMINI_API_KEY) return { googleAiKey: process.env.GEMINI_API_KEY };
+      try {
+        return await getAiSettings();
+      } catch {
+        return null;
+      }
+    })(),
+    (async () => {
+      try {
+        return await getKesherSettings();
+      } catch {
+        return null;
+      }
+    })(),
+    (async () => {
+      try {
+        await adminDb.collection("configs").limit(1).get();
+        return true;
+      } catch (error) {
+        console.warn("Database status check failed:", error);
+        return false;
+      }
+    })(),
+    (async () => {
+      try {
+        return await getGlobalSettings();
+      } catch {
+        return null;
+      }
+    })()
+  ]);
+
+  const geminiActive = !!(process.env.GEMINI_API_KEY || aiSettings?.googleAiKey);
+  const kesherActive = !!(kesherSettings?.isActive);
+
+  const session = await auth();
+  const isImpersonating = !!(session?.user as any)?.isImpersonating;
+
+  return (
+    <DashboardShellTest
+      geminiActive={geminiActive}
+      kesherActive={kesherActive}
+      dbActive={dbActive}
+      modal={modal}
+      miniSiteSlug={globalSettings?.miniSiteSlug}
+      isImpersonating={isImpersonating}
+    >
+      <Suspense fallback={<div className="h-64 w-full animate-pulse bg-muted rounded-[2rem]" />}>
+        {children}
+      </Suspense>
+    </DashboardShellTest>
+  );
+}
diff --git a/src/app/dashboard-test/page.tsx b/src/app/dashboard-test/page.tsx
new file mode 100644
index 0000000..c53cce6
--- /dev/null
+++ b/src/app/dashboard-test/page.tsx
@@ -0,0 +1,57 @@
+import { getAllServices } from "@/features/services/actions";
+import { adminDb } from "@/lib/firebase-admin";
+import { auth } from "@/lib/auth";
+import { getGlobalSettings } from "@/features/settings/actions";
+import { DashboardClientTest } from "./DashboardClientTest";
+
+async function getUserId(): Promise<string> {
+  const session = await auth();
+  if (session?.user?.id) {
+    return session.user.id;
+  }
+  throw new Error("Unauthorized");
+}
+
+export default async function DashboardPage() {
+  const services = await getAllServices();
+  const ownerId = await getUserId();
+  const session = await auth();
+  const userName = session?.user?.name || session?.user?.email?.split('@')[0] || "משתמש";
+
+  // Query CRM stats for current owner
+  const [contactCount, totalSpentResult, globalSettings] = await Promise.all([
+    adminDb.collection("contacts")
+      .where("ownerId", "==", ownerId)
+      .where("status", "==", "active")
+      .get()
+      .then((s: any) => s.size)
+      .catch(() => 0),
+    adminDb.collection("contacts")
+      .where("ownerId", "==", ownerId)
+      .where("status", "==", "active")
+      .get()
+      .then((snap: any) => {
+        let sum = 0;
+        snap.docs.forEach((doc: any) => {
+          sum += doc.data().total_spent || 0;
+        });
+        return sum;
+      })
+      .catch(() => 0),
+    getGlobalSettings(ownerId)
+  ]);
+
+  return (
+    <div className="w-full relative min-h-full pt-0 md:pt-8" dir="rtl">
+      <div className="max-w-7xl mx-auto">
+        <DashboardClientTest
+          initialSettings={globalSettings}
+          initialServices={services}
+          contactCount={contactCount}
+          totalSpentResult={totalSpentResult}
+          userName={userName}
+        />
+      </div>
+    </div>
+  );
+}
